$(".nav-link").on("click",(function(){$(".navbar-collapse").collapse("hide")})),$(".carousel").carousel({interval:!1});const scrollToTopButton=document.getElementById("floating-btn"),scrollFunc=()=>{let y=window.scrollY;scrollToTopButton.className=y>100?"show":"hide"};window.addEventListener("scroll",scrollFunc);const date=(new Date).getFullYear();$("#date").text(date);